FROM jsonb_to_recordset('[{"id": "cap-113-english-reading-passage-22", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-113-english-reading", "question_type": "reading_passage", "question_text": "(22-23)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "It was around eight o’clock on Saturday night. Philip was at home with his little\nbrother, Jason. Jason was hungry and kept crying. But Philip couldn’t cook and their\nfather was not home yet because he was working late in the office.  So Philip decided to\ntake Jason out for some food.\nHalf an hour later, when they came back home, Philip was surprised to find that their\nfather was talking to the police and a woman outside their house. He didn’t know who\nthe woman was. She looked scared and stood behind the police. Philip’s father was very\nangry and kept shouting, “I didn’t do anything wrong! I forgot my keys and was just\ntrying to get into MY OWN HOUSE!”  But the police didn’t believe him until Philip ran\nto them and explained everything.\nThe police told Philip that the woman called 110 when she saw Philip’s father trying\nto get into a house through a window. That was how it all happened.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "75b1ef57c78d", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": null, "intro_line": "(22-23)", "child_qnums": [22, 23]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-english-reading-passage-24", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-113-english-reading", "question_type": "reading_passage", "question_text": "(24-25)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": " oven 烤爐", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "75b1ef57c78d", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": null, "intro_line": "(24-25)", "child_qnums": [24, 25]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-english-reading-passage-26", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-113-english-reading", "question_type": "reading_passage", "question_text": "(26-27)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "75b1ef57c78d", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": null, "intro_line": "(26-27)", "child_qnums": [26, 27]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-english-reading-passage-28", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-113-english-reading", "question_type": "reading_passage", "question_text": "(28-29)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Yan lived a good life in a big house. One day he invited a friend to dinner at his\nhouse. However, on the dinner table there was only one small dish of one small fish.\nThe friend looked quietly at the fish. It was no bigger than a finger.\nThen he asked Yan if he could borrow a lamp.\n“What for?” Yan asked.\n“Well, it’s so dark in here,” the friend said with a dry smile,\n“I can’t see the other delicious dishes you’ve prepared for me.”\nChang kept a lot of ducks and chickens on his farm. One day, his best friend\ncame to visit him. At noon, Chang told his friend that he couldn’t let him stay for lunch\nbecause there wasn’t much food to eat. The friend looked out at Chang’s farm animals\nfor a moment. Then he asked Chang if he had a big knife.\n“Yes, but what for?” Chang asked.\n“I’m thinking about killing the horse I rode here so we’ll\nhave something for lunch,” the friend said.\n“But how are you going to go home without it?”\n“Well, you wouldn’t mind lending me one of your many\nducks or chickens so I can ride it home, would you?”", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "75b1ef57c78d", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": null, "intro_line": "(28-29)", "child_qnums": [28, 29]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-english-reading-passage-30", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-113-english-reading", "question_type": "reading_passage", "question_text": "(30-32)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Usually, people visit bookstores to buy books. But those who walk\ninto Cotoha come to see its owner, Chen Bing-Hong. They bring him\nbooks with different problems. Some have lost their covers, some are\nmissing a few pages, and some have pages that are falling out. Chen can\nalways fix the books and make them whole again.\nChen sees himself as a doctor. He says that books, like people, get\nsick and need help. In Taiwan, there are not many “doctors” like him,\nand most of them work for big libraries and museums. If big libraries and\nmuseums are hospitals, Chen’s bookstore is a health center. Big libraries\nand museums fix important old books with serious problems, and Chen\nhelps people with books that have smaller problems. However, the smaller\nsize of the problems doesn’t mean Chen’s job is less important.\nChen gave an example of a science book he once worked on. It was\nvery old and half of its cover was lost. Its owner still wanted to keep it\nbecause it was a gift from a teacher who helped him follow his dream of\nstudying science. When he got his book back, he was very surprised at the\nnew-old book. He felt he was brought back to the days with his teacher.\nSeeing the owner’s smile made Chen happy, because smiles like that are\nwhat his magic is for.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "75b1ef57c78d", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": null, "intro_line": "(30-32)", "child_qnums": [30, 31, 32]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-english-reading-passage-33", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-113-english-reading", "question_type": "reading_passage", "question_text": "(33-35)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "\u0007A Delicious Surprise and Welcome Change\nBy Karl Falk, June 1, 2016\nIn Austria, there are not many restaurants like Habibi\n& Hawara. Here you can enjoy Austrian and Syrian\nfood together. Two Austrians, Martin Rohla and\nDavid Kreytenberg, started this yummy plan from\ntheir experience of working with refugees.\nEvery year, thousands of people have to leave\ntheir homes and families because of war in their\ncountries. So many of them go to Austria that some\npeople in the country think they have become a problem. They are afraid refugees\nmay take away their jobs and they don’t feel safe around them, either. But Rohla\nand Kreytenberg would beg to differ: The refugees don’t have to be a problem.\nThey want to help them start a new life. They invited refugees to meetings and\nfound that some of them were cooks back in Syria. So the idea of Habibi & Hawara\nwas born—a restaurant that brings together Austrian and Syrian food. “The two\nworlds far away from each other meet together,” Kreytenberg said.\nBut Rohla and Kreytenberg want to do more than just give the refugees work. They\nwant their best workers to buy the restaurant in the end. They hope that Habibi &\nHawara is not just a one-time plan and that other Austrians will join them and help\nmore refugees.\n refugee 難民       war 戰爭", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "75b1ef57c78d", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": null, "intro_line": "(33-35)", "child_qnums": [33, 34, 35]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-english-reading-passage-36", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-113-english-reading", "question_type": "reading_passage", "question_text": "(36-39)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "VOICES OF PEOPLE\nIf you want to learn about bringing back extinct animals, reading\nJohn Smith’s Back from the Dead is a good start. But I have to say\nI can’t agree with everything he says.\nEllen Zimmer\nFrom his book, I can see Smith is an advocate of bringing extinct animals back. He\nsays we have lost many animals because we made their living spaces too dirty. He also\nthinks we must do everything we can to bring them back. However, I don’t know how\nmuch time and money we would need to make the world a better place for them, and\nhonestly no one knows if they could actually come back.\nSmith also says that bringing back extinct animals may be good for us. He talks about\nan extinct frog that grew tadpoles in its stomach. Some women’s babies die before they\nare born, and Smith believes bringing back the frog may be an answer to the problem.\nAccording to him, by studying how the tadpoles grow inside the frog’s stomach, we\nmight be able to find new ways to help these women successfully keep their babies.  But\nI don’t think things are as easy as Smith thinks. We have spent ten years and millions\nof dollars on this kind of frog, but all we have got are only a few dead frog eggs. If we\ncan’t see a real frog, how can we be sure women will get the help they need?\nDr. Solomon Wang from the Animal Saving Office says the study of bringing back\nextinct animals is “throwing good money after bad.”  And he’s right.  A lot of hard work\nhas been put into this expensive dream, but we haven’t seen anything come out of it.\nSo should we still keep going down this road?\n extinct 絕種的         tadpole 蝌蚪", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "75b1ef57c78d", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": null, "intro_line": "(36-39)", "child_qnums": [36, 37, 38, 39]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-english-reading-passage-40", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-113-english-reading", "question_type": "reading_passage", "question_text": "(40-43)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "A HISTORY LESSON ON THE PANDEMIC                                        2020.10.29\nSince the Covid-19 pandemic started, people have begun “social distancing”—\nkeeping a safe space between you and anyone you don’t live with. Though it\nhas been a very popular topic this year, social distancing 40 . In fact, it was\nwidely used in the U.S. in the flu pandemic in 1918. But how well did it work? The\nAmericans’ experience can tell us whether it really saved lives.\nFrom the picture, we can see that 41 started social distancing earlier than\nthe other three cities. This helped the city keep the number of deaths down. Besides\ntaking early action, keeping the action long enough was also important in fighting\nthe pandemic. The picture shows that Portland and Denver did well in the first few\nweeks. However, both cities 42 , and the numbers of deaths climbed again.\nBut there was one thing Portland did right. The city used several ways of social\ndistancing at the same time to deal with the pandemic. 43 , sick people were kept\naway from healthy ones; schools were closed; public activities were not allowed. All\nthese were useful in keeping people safe.\nThe lessons of the 1918 pandemic bring us hope. While we are still learning to\nfight Covid-19, social distancing may be the best way to get us through the dark days,\nat least for now.\n pandemic （疾病的）大流行         per 每(一)", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "75b1ef57c78d", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": null, "intro_line": "(40-43)", "child_qnums": [40, 41, 42, 43]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
